mapper.select:
SELECT COUNT(*)
FROM financial_node_snapshot
WHERE user_id = #{userId}
          AND year = #{year}
          AND month = #{month}

mapper.update:
UPDATE financial_node_snapshot cur
    JOIN financial_node_snapshot prev
ON cur.template_id = prev.template_id
    AND prev.year = #{prevYear}
    AND prev.month = #{prevMonth}
    AND prev.user_id = #{userId, jdbcType=VARCHAR}
    SET cur.current_balance = prev.current_balance
WHERE cur.user_id = #{userId, jdbcType=VARCHAR}
  AND cur.year = #{year}
  AND cur.month = #{month}
  AND cur.type = 'ASSET'

mapper.select:
SELECT id,
       name,
       type,
       monthly_amount AS monthlyAmount
FROM financial_node_snapshot
WHERE user_id = #{userId}
          AND year = #{year}
          AND month = #{month}
ORDER BY id

mapper.update:
UPDATE financial_node_snapshot
SET monthly_amount = #{amount}
WHERE user_id = #{userId}
  AND id = #{snapshotId}

UPDATE financial_node_snapshot
SET monthly_amount = #{amount}
WHERE user_id = #{userId}
          AND year = #{year}
          AND month = #{month}
  AND name = #{name}

UPDATE flow_snapshot f
    JOIN financial_node_snapshot n
ON f.to_snapshot_id = n.id
    SET f.amount = n.monthly_amount
WHERE n.user_id = #{userId}
  AND n.year = #{year}
  AND n.month = #{month}
